<?php

/**
 * Recurring task definitions (owner-managed in Settings).
 *
 * Two kinds:
 *  - "monthly": fully editable — title, assignee, days of month. The daily cron
 *    adds the task to the assignee's to-dos on the chosen days.
 *  - "system": generated by dedicated logic (e.g. post-course tasks). Schedule is
 *    fixed; only the title text is editable. Shown read-only otherwise.
 */

define('RECURRING_FILE',       dirname(__DIR__) . '/data/recurring_tasks.json');
define('RECURRING_STATE_FILE', dirname(__DIR__) . '/data/recurring_done.json');

