    $sched = 'A doua zi după fiecare curs';
    return [
        ['id' => 'sys_pc_1', 'type' => 'system', 'system_key' => 'post_course', 'assigned_to' => 'andy',
         'title' => 'Adaugă foto-video Drive de la cursul {curs}', 'schedule' => $sched,
         'description' => 'Generat automat lui Andy a doua zi după fiecare curs. {curs} = numele cursului.'],
        ['id' => 'sys_pc_2', 'type' => 'system', 'system_key' => 'post_course', 'assigned_to' => 'andy',
         'title' => 'Modifică denumirile videoclipurilor', 'schedule' => $sched,
         'description' => 'Generat automat lui Andy a doua zi după fiecare curs.'],
        ['id' => 'sys_pc_3', 'type' => 'system', 'system_key' => 'post_course', 'assigned_to' => 'andy',
         'title' => 'Cere factură {speaker}', 'schedule' => $sched,
         'description' => 'Generat automat lui Andy a doua zi după fiecare curs. {speaker} = speakerul cursului.'],
        ['id' => 'sys_pc_4', 'type' => 'system', 'system_key' => 'post_course', 'assigned_to' => 'andy',
         'title' => 'Trimite formular feedback {speaker}', 'schedule' => $sched,
         'description' => 'Generat automat lui Andy a doua zi după fiecare curs. {speaker} = speakerul cursului.'],
        ['id' => 'sys_publish', 'type' => 'system', 'system_key' => 'course_published', 'assigned_to' => 'andy',
         'title' => 'Adaugă cursul {curs} pe [Off the Couch](https://offthecouch.city/) și [Mellon](https://mellon.life/discover)',
         'schedule' => 'Când un curs primește link',
